{"content": "<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Paradise Bay Beach Resort - Your Luxury Escape Awaits</title>
    <style>
        /* Reset styles */
        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
            font-family: 'Georgia', 'Times New Roman', serif;
            background-color: #f5f5f5;
            line-height: 1.6;
            color: #333333;
        }

        /* Container */
        .email-container {
            max-width: 600px;
            margin: 0 auto;
            background-color: #ffffff;
        }

        /* Header */
        .header {
            background: linear-gradient(135deg, #1a5f7a 0%, #2e8b8b 100%);
            padding: 40px 30px;
            text-align: center;
        }

        .header h1 {
            color: #ffffff;
            font-size: 32px;
            font-weight: 400;
            letter-spacing: 2px;
            margin-bottom: 10px;
        }

        .header .tagline {
            color: rgba(255,255,255,0.9);
            font-size: 16px;
            font-style: italic;
        }

        /* Hero Image Placeholder */
        .hero-image {
            background-color: #1a5f7a;
            height: 250px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: rgba(255,255,255,0.7);
            font-size: 14px;
        }

        /* Main Content */
        .content {
            padding: 40px 30px;
        }

        .content h2 {
            color: #1a5f7a;
            font-size: 24px;
            font-weight: 400;
            margin-bottom: 20px;
            text-align: center;
        }

        .content p {
            margin-bottom: 20px;
            font-size: 16px;
        }

        /* Features Section */
        .features {
            margin: 30px 0;
        }

        .feature-item {
            display: flex;
            align-items: flex-start;
            margin-bottom: 20px;
            padding: 15px;
            background-color: #f9f9f9;
            border-left: 4px solid #2e8b8b;
        }

        .feature-icon {
            font-size: 24px;
            margin-right: 15px;
            min-width: 30px;
        }

        .feature-text h3 {
            color: #1a5f7a;
            font-size: 18px;
            font-weight: 600;
            margin-bottom: 5px;
        }

        .feature-text p {
            font-size: 14px;
            margin: 0;
            color: #666666;
        }

        /* Special Offers */
        .offers-section {
            background-color: #f0f7f7;
            padding: 30px;
            margin: 30px 0;
            border-radius: 8px;
            text-align: center;
        }

        .offers-section h3 {
            color: #1a5f7a;
            font-size: 22px;
            margin-bottom: 20px;
        }

        .offer-item {
            display: inline-block;
            margin: 10px;
            padding: 15px 25px;
            background-color: #ffffff;
            border: 2px solid #2e8b8b;
            border-radius: 50px;
            font-size: 14px;
            color: #1a5f7a;
        }

        /* CTA Button */
        .cta-button {
            display: block;
            width: 280px;
            margin: 30px auto;
            padding: 18px 30px;
            background-color: #1a5f7a;
            color: #ffffff !important;
            text-decoration: none;
            text-align: center;
            font-size: 16px;
            font-weight: 600;
            letter-spacing: 1px;
            border-radius: 4px;
            transition: background-color 0.3s;
        }

        .cta-button:hover {
            background-color: #154d63;
        }

        /* Contact Info */
        .contact-info {
            text-align: center;
            padding: 30px;
            background-color: #1a5f7a;
            color: #ffffff;
        }

        .contact-info p {
            margin: 8px 0;
            font-size: 14px;
        }

        .contact-info a {
            color: #ffffff;
            text-decoration: underline;
        }

        /* Social Links */
        .social-links {
            text-align: center;
            padding: 20px;
            border-top: 1px solid #eeeeee;
        }

        .social-links span {
            display: inline-block;
            margin: 0 10px;
            color: #1a5f7a;
            font-size: 14px;
        }

        /* Footer */
        .footer {
            text-align: center;
            padding: 20px;
            font-size: 12px;
            color: #999999;
        }

        .footer p {
            margin: 5px 0;
        }

        /* Responsive */
        @media only screen and (max-width: 600px) {
            .email-container {
                width: 100% !important;
            }

            .header {
                padding: 30px 20px;
            }

            .header h1 {
                font-size: 26px;
            }

            .content {
                padding: 30px 20px;
            }

            .offer-item {
                display: block;
                margin: 10px 0;
            }
        }
    </style>
</head>
<body>
    <div class="email-container">

        <!-- Header -->
        <div class="header">
            <h1>PARADISE BAY BEACH RESORT</h1>
            <p class="tagline">Where Dreams Meet the Sea</p>
        </div>

        <!-- Hero Image Placeholder -->
        <div class="hero-image">
            [Hero Image: Pristine Beach & Turquoise Waters]
        </div>

        <!-- Main Content -->
        <div class="content">
            <h2>Your Tropical Paradise Awaits</h2>

            <p>Experience the ultimate getaway at Paradise Bay Beach Resort, where crystal-clear waters meet pristine white sandy beaches. Located on the stunning coast of Hawaii, our resort offers an unforgettable escape from everyday life.</p>

            <!-- Features -->
            <div class="features">
                <div class="feature-item">
                    <span class="feature-icon">🏨</span>
                    <div class="feature-text">
                        <h3>Luxury Suites</h3>
                        <p>Spacious oceanfront rooms with private balconies and premium amenities</p>
                    </div>
                </div>

                <div class="feature-item">
                    <span class="feature-icon">🍽️</span>
                    <div class="feature-text">
                        <h3>World-Class Dining</h3>
                        <p>Five restaurants featuring local and international cuisine</p>
                    </div>
                </div>

                <div class="feature-item">
                    <span class="feature-icon">💆</span>
                    <div class="feature-text">
                        <h3>Spa & Wellness</h3>
                        <p>Full-service spa with Hawaiian-inspired treatments</p>
                    </div>
                </div>

                <div class="feature-item">
                    <span class="feature-icon">🏖️</span>
                    <div class="feature-text">
                        <h3>Private Beach & Water Sports</h3>
                        <p>Snorkeling, kayaking, paddleboarding, and more</p>
                    </div>
                </div>

                <div class="feature-item">
                    <span class="feature-icon">⛳</span>
                    <div class="feature-text">
                        <h3>Championship Golf</h3>
                        <p>18-hole course with stunning ocean views</p>
                    </div>
                </div>
            </div>

            <!-- Special Offers -->
            <div class="offers-section">
                <h3>Special Offers</h3>
                <div class="offer-item">🎁 20% Off Your First Stay</div>
                <div class="offer-item">☕ Free Breakfast Daily</div>
                <div class="offer-item">✈️ Complimentary Airport Transfers</div>
                <div class="offer-item">🌊 Ocean View Upgrade</div>
            </div>

            <!-- CTA Button -->
            <a href="https://www.paradisbayresort.com" class="cta-button">BOOK YOUR ESCAPE</a>

            <p style="text-align: center; font-size: 14px; color: #666;">
                Or call us at <strong>1-800-PARADISE</strong>
            </p>
        </div>

        <!-- Contact Info -->
        <div class="contact-info">
            <p><strong>Paradise Bay Beach Resort</strong></p>
            <p>Hawaii, United States</p>
            <p><a href="mailto:reservations@paradisebayresort.com">reservations@paradisebayresort.com</a></p>
            <p><a href="https://www.paradisbayresort.com">www.paradisbayresort.com</a></p>
        </div>

        <!-- Social Links -->
        <div class="social-links">
            <span>📘 @ParadiseBayResort</span>
            <span>📸 @ParadiseBayResort</span>
            <span>🐦 @ParadiseBayResort</span>
        </div>

        <!-- Footer -->
        <div class="footer">
            <p>© 2024 Paradise Bay Beach Resort. All rights reserved.</p>
            <p>You received this email because you're subscribed to our newsletter.</p>
            <p><a href="#" style="color: #999;">Unsubscribe</a> | <a href="#" style="color: #999;">Privacy Policy</a></p>
        </div>

    </div>
</body>
</html>", "path": "05_PROMO/email_templates/luxury_resort_email.html"}

